export interface CSVOptions {
  delimiter?: string;
  quote?: string;
  lineSeparator?: string;
}

export interface CSVError {
  row: number;
  message: string;
}

export type CSVRow = Record<string, any>;

export interface CSVResult {
  rows: CSVRow[];
  headers: string[];
  errors: CSVError[];
  filter(predicate: (row: CSVRow) => boolean): CSVResult;
  sum(column: string): number;
  average(column: string): number;
  count(): number;
  groupBy(column: string): Map<any, CSVRow[]>;
}

interface FieldRecord {
  raw: string;
  quoted: boolean;
}

const DEFAULT_DELIMITER = ',';
const DEFAULT_QUOTE = '"';
const DEFAULT_LINE_SEPARATOR = '\n';

export function parseCSV(input: string, options: CSVOptions = {}): CSVResult {
  const delimiter = options.delimiter ?? DEFAULT_DELIMITER;
  const quote = options.quote ?? DEFAULT_QUOTE;
  const lineSeparator = options.lineSeparator || DEFAULT_LINE_SEPARATOR;

  const normalizedInput = normalizeLineBreaks(input, lineSeparator);
  const { rows: parsedRows, rowNumbers } = tokenizeRows(
    normalizedInput,
    delimiter,
    quote,
    lineSeparator
  );

  if (parsedRows.length === 0) {
    return buildResult([], [], []);
  }

  const headerFieldRecords = parsedRows[0];
  const headers = headerFieldRecords.map((field) => field.raw);
  const rows: CSVRow[] = [];
  const errors: CSVError[] = [];

  for (let i = 1; i < parsedRows.length; i++) {
    const fieldRecords = parsedRows[i];
    const rowNumber = rowNumbers[i];

    if (fieldRecords.length !== headers.length) {
      errors.push({
        row: rowNumber,
        message: `Expected ${headers.length} columns but found ${fieldRecords.length}`,
      });
      continue;
    }

    const record: CSVRow = {};
    for (let columnIndex = 0; columnIndex < headers.length; columnIndex++) {
      const header = headers[columnIndex];
      const fieldRecord = fieldRecords[columnIndex];
      record[header] = coerceField(fieldRecord);
    }

    rows.push(record);
  }

  return buildResult(rows, headers, errors);
}

function normalizeLineBreaks(input: string, lineSeparator: string): string {
  if (lineSeparator === '\n') {
    return input.replace(/\r\n/g, '\n').replace(/\r/g, '\n');
  }
  return input;
}

function tokenizeRows(input: string, delimiter: string, quote: string, lineSeparator: string) {
  const rows: FieldRecord[][] = [];
  const rowNumbers: number[] = [];

  let currentRow: FieldRecord[] = [];
  let currentField = '';
  let insideQuotes = false;
  let fieldWasQuoted = false;
  let rowNumber = 1;

  const separatorLength = lineSeparator.length;
  const shouldDetectSeparator = separatorLength > 0;

  const pushField = () => {
    currentRow.push({ raw: currentField, quoted: fieldWasQuoted });
    currentField = '';
    fieldWasQuoted = false;
  };

  const pushRow = () => {
    rows.push(currentRow);
    rowNumbers.push(rowNumber);
    rowNumber += 1;
    currentRow = [];
  };

  for (let index = 0; index < input.length; index++) {
    const char = input[index];

    if (insideQuotes) {
      if (char === quote) {
        if (index + 1 < input.length && input[index + 1] === quote) {
          currentField += quote;
          index += 1;
        } else {
          insideQuotes = false;
        }
      } else {
        currentField += char;
      }
      continue;
    }

    if (shouldDetectSeparator && input.substring(index, index + separatorLength) === lineSeparator) {
      pushField();
      pushRow();
      index += separatorLength - 1;
      continue;
    }

    if (char === delimiter) {
      pushField();
      continue;
    }

    if (char === quote && currentField === '') {
      insideQuotes = true;
      fieldWasQuoted = true;
      continue;
    }

    currentField += char;
  }

  const hasTrailingData = currentRow.length > 0 || currentField !== '' || fieldWasQuoted;
  if (hasTrailingData) {
    pushField();
    pushRow();
  }

  return { rows, rowNumbers };
}

function coerceField(field: FieldRecord): any {
  const raw = field.quoted ? field.raw : field.raw.trim();

  if (raw === '') {
    return null;
  }

  const lower = raw.toLowerCase();
  if (lower === 'null') {
    return null;
  }

  if (lower === 'true') {
    return true;
  }

  if (lower === 'false') {
    return false;
  }

  if (isNumericString(raw)) {
    return Number(raw);
  }

  return raw;
}

const NUMERIC_PATTERN = /^[-+]?(?:\d+(?:\.\d*)?|\.\d+)$/;

function isNumericString(value: string): boolean {
  if (!NUMERIC_PATTERN.test(value)) {
    return false;
  }
  const num = Number(value);
  return Number.isFinite(num);
}

function buildResult(rows: CSVRow[], headers: string[], errors: CSVError[]): CSVResult {
  const factory = (rowSet: CSVRow[]) => ({
    rows: rowSet,
    headers,
    errors,
    filter(predicate: (row: CSVRow) => boolean) {
      return factory(rowSet.filter(predicate));
    },
    sum(column: string) {
      return rowSet.reduce((acc, row) => {
        const value = row[column];
        if (typeof value === 'number') {
          return acc + value;
        }
        return acc;
      }, 0);
    },
    average(column: string) {
      const numericValues = rowSet.filter((row) => typeof row[column] === 'number') as CSVRow[];
      if (numericValues.length === 0) {
        return 0;
      }
      const total = numericValues.reduce((acc, row) => acc + (row[column] as number), 0);
      return total / numericValues.length;
    },
    count() {
      return rowSet.length;
    },
    groupBy(column: string) {
      const grouped = new Map<any, CSVRow[]>();
      for (const row of rowSet) {
        const key = row[column];
        const bucket = grouped.get(key) ?? [];
        bucket.push(row);
        grouped.set(key, bucket);
      }
      return grouped;
    },
  }))(
    rows
  );

  return factory(rows);
}
